sql:
SELECT hs_code_id, AVG(tariff_rate) AS avg_tariff_rate
FROM tariffs
GROUP BY hs_code_id;

SELECT COUNT(*) AS total_shipments_cleared
FROM customs_clearances
WHERE clearance_status = 'Cleared';

SELECT status_date, status
FROM shipment_status
WHERE shipment_id = 1;

SELECT shipment_id, COUNT(*) AS container_count
FROM shipment_containers
GROUP BY shipment_id;

SELECT shipment_id, MAX(status_date) AS latest_status_date
FROM shipment_status
GROUP BY shipment_id;

SELECT total_value, quantity
FROM shipment_goods
WHERE shipment_id = 0;

SELECT goods_description, SUM(total_value) AS total_shipment_value
FROM shipment_goods
GROUP BY goods_description;

external_knowledge:
- "Large shipments" refers to shipments with a total value greater than 10,000; 
- "Long-distance shipments" refers to shipments with a route distance of more than 500 kilometers;
- "Delivered shipments" refers to shipments with a status of 'Delivered' as indicated in the shipment status table.
